SELECT cell_line_name, growth_condition
FROM cell_lines
ORDER BY growth_condition;

SELECT cell_line_name
FROM cell_lines
ORDER BY cell_line_name ASC;

SELECT cell_line_name, clin_subtype_id, hr_status_consensus_id, growth_condition
FROM cell_lines
WHERE authentication_date = (SELECT MIN(authentication_date) FROM cell_lines);
